import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void lShapeBeatsSmallIsland() {
        int[][] grid = {
            {1, 1, 0},
            {1, 0, 0},
            {0, 0, 1}
        };
        assertEquals(3, new Solution().maxAreaOfIsland(grid));
    }

    @Test
    void entireGridOneIsland() {
        int[][] grid = {
            {1, 1, 1},
            {1, 1, 1}
        };
        assertEquals(6, new Solution().maxAreaOfIsland(grid));
    }

    @Test
    void allWater() {
        int[][] grid = {
            {0, 0},
            {0, 0}
        };
        assertEquals(0, new Solution().maxAreaOfIsland(grid));
    }

    @Test
    void singleLandCell() {
        int[][] grid = {{1}};
        assertEquals(1, new Solution().maxAreaOfIsland(grid));
    }

    @Test
    void emptyGrid() {
        int[][] grid = {};
        assertEquals(0, new Solution().maxAreaOfIsland(grid));
    }

    @Test
    void multipleEqualSizedIslands() {
        // Two islands of size 2 — max is 2
        int[][] grid = {
            {1, 1, 0, 1, 1},
            {0, 0, 0, 0, 0}
        };
        assertEquals(2, new Solution().maxAreaOfIsland(grid));
    }

    @Test
    void narrowCorridor() {
        // A single-column island of height 4
        int[][] grid = {
            {0, 1},
            {0, 1},
            {0, 1},
            {0, 1}
        };
        assertEquals(4, new Solution().maxAreaOfIsland(grid));
    }
}
